```javascript
// daily_pipeline.js
// 用法: node scripts/daily_pipeline.js [--no-ai] [--p0-only]

const fs = require('fs');
const path = require('path');
const ExcelJS = require('exceljs');

// Configuration
const DATA_DIR = path.join(__dirname, '..', 'data');
const CONFIG_DIR = path.join(__dirname, '..', 'config');
const OUTPUT_DIR = path.join(__dirname, '..', 'output');

// Main function
async function main() {
  const args = process.argv.slice(2);
  const skipAI = args.includes('--no-ai');
  const p0Only = args.includes('--p0-only');

  // Step 1: Load data
  const customers = loadData();

  // Step 2: Load config
  const tierRules = loadJSON(path.join(CONFIG_DIR, 'tier_rules.json'));
  const scoring = loadJSON(path.join(CONFIG_DIR, 'scoring.json'));

  // Step 3: Classify
  const classified = customers.map(c => classifyCustomer(c, tierRules));

  // Step 4: Score & sort
  const scored = classified.map(c => scoreCustomer(c, scoring, tierRules));
  scored.sort((a, b) => b.score - a.score);

  // Step 5: Generate outputs
  const today = new Date().toISOString().slice(0, 10);
  await generateExcel(scored, tierRules, today);
  generateActionList(scored, tierRules, scoring, today);

  // Step 6: Stats
  printStats(scored, tierRules);
}

main().catch(console.error);
```

Let me think about each function more carefully:

### classifyCustomer(customer, rules)
- Try P0 rules first, then P1, P2, P3, fallback to P4
- For each tier's rules, check if any rule matches (OR within tier)
- A rule matches if all conditions match (AND within rule)

### evaluateCondition(customer, condition)
- condition has {field, op, value}
- ops: eq, neq, gt, gte, lt, lte, in, contains

### scoreCustomer(customer, scoring, rules)
- Start with base score based on tier (P0=100, P1=70, P2=45, P3=20, P4=0)
- Add/subtract based on scoring weights
- Apply bonuses and penalties

Let me write the full script now.

