1	/**
2	 * OKKI 每日客户分析一键流水线
3	 *
4	 * 用法：
5	 *   node scripts/daily_pipeline.js           完整流程
6	 *   node scripts/daily_pipeline.js --no-ai   跳过AI话术
7	 *   node scripts/daily_pipeline.js --p0-only 只看P0客户
8	 *
9	 * 输入：data/s1_enhanced.json（分类特征数据）
10	 * 输出：output/daily_YYYY-MM-DD.xlsx（Excel看板）
11	 *       output/actions_YYYY-MM-DD.md（行动清单）
12	 */
13	
14	const fs = require('fs');
15	const path = require('path');
16	const ExcelJS = require('exceljs');
17	
18	const DATA_DIR = path.join(__dirname, '..', 'data');
19	const CONFIG_DIR = path.join(__dirname, '..', 'config');
20	const OUTPUT_DIR = path.join(__dirname, '..', 'output');
21	
22	// ===================== 工具函数 =====================
23	
24	function loadJSON(filepath) {
25	  if (!fs.existsSync(filepath)) {
26	    console.error(`[ERROR] 文件不存在: ${filepath}`);
27	    return null;
28	  }
29	  return JSON.parse(fs.readFileSync(filepath, 'utf-8'));
30	}
31	
32	function todayStr() {
33	  return new Date().toISOString().slice(0, 10);
34	}
35	
36	// ===================== 规则引擎 =====================
37	
38	function evalCondition(customer, cond) {
39	  const val = customer[cond.field];
40	  if (val === undefined) return false;
41	
42	  switch (cond.op) {
43	    case 'eq': return val === cond.value;
44	    case 'neq': return val !== cond.value;
45	    case 'gt': return val > cond.value;
46	    case 'gte': return val >= cond.value;
47	    case 'lt': return val < cond.value;
48	    case 'lte': return val <= cond.value;
49	    case 'in': return Array.isArray(cond.value) && cond.value.includes(val);
50	    case 'contains': return typeof val === 'string' && val.toLowerCase().includes(String(cond.value).toLowerCase());
51	    default: return false;
52	  }
53	}
54	
55	function matchRule(customer, rule) {
56	  if (rule.all) return rule.all.every(c => evalCondition(customer, c));
57	  if (rule.any) return rule.any.some(c => evalCondition(customer, c));
58	  return false;
59	}
60	
61	/**
62	 * 对单个客户做五梯队分类。
63	 * 按 P0→P1→P2→P3 顺序匹配，命中即停止。都未命中归入 P4。
64	 */
65	function classifyCustomer(customer, rules) {
66	  for (const tier of ['p0', 'p1', 'p2', 'p3']) {
67	    const tierDef = rules[tier];
68	    if (!tierDef || !tierDef.rules) continue;
69	    for (const rule of tierDef.rules) {
70	      if (matchRule(customer, rule)) {
71	        return { ...customer, tier, tierLabel: tierDef.label, tierReason: rule.name };
72	      }
73	    }
74	  }
75	  return { ...customer, tier: 'p4', tierLabel: rules.p4.label, tierReason: rules.p4.description };
76	}
77	
78	// ===================== 评分引擎 =====================
79	
80	const TIER_BASE = { p0: 100, p1: 70, p2: 45, p3: 20, p4: 0 };
81	
82	function scoreCustomer(customer, scoring, rules) {
83	  const w = scoring.weights;
84	  let score = TIER_BASE[customer.tier] || 0;
85	
86	  // 时效惩罚：每多1天扣分
87	  score -= (customer.daysAgo || 0) * w.daysAgo_penalty.value;
88	
89	  // 客户最近回复加分
90	  if (customer.lastCustomerMsgDays !== undefined && customer.lastCustomerMsgDays <= 1) {
91	    score += w.lastCustomerMsg_bonus.value;
92	  }
93	
94	  // 核心市场加分
95	  if (rules.core_markets.includes(customer.country)) {
96	    score += w.core_market_bonus.value;
97	  }
98	
99	  // 下单信号加分
100	  if (customer.hasOrderSignal) {
101	    score += w.order_signal_bonus.value;
102	  }
103	
104	  // PI+地址加分
105	  if (customer.hasPI && customer.hasAddress) {
106	    score += w.pi_address_bonus.value;
107	  }
108	
109	  // 高互动加分
110	  if (customer.realMsgs >= 30) {
111	    score += w.high_engagement_bonus.value;
112	  }
113	
114	  // 客户消息占比高加分
115	  if (customer.cRatio >= 40) {
116	    score += w.customer_reply_bonus.value;
117	  }
118	
119	  // 沉默惩罚
120	  const silence = rules.silence_warnings[customer.tier];
121	  if (silence && customer.lastCustomerMsgDays >= silence.danger) {
122	    score -= w.silence_penalty.value;
123	  }
124	
125	  return { ...customer, score };
126	}
127	
128	// ===================== 阶段判断 =====================
129	
130	function determineStage(customer) {
131	  if (customer.hasPI && customer.hasAddress && customer.daysAgo <= 7) {
132	    return { stage: 1, label: '待确认付款', action: '确认PI信息无误 → 提醒付款 → 锁定排产。时效：24h内。' };
133	  }
134	  if (customer.realMsgs >= 15 && customer.daysAgo <= 3) {
135	    return { stage: 2, label: '谈判中·近期活跃', action: '补全信息缺口 → 给价格区间 → 引导下一步。时效：48h内。' };
136	  }
137	  if (customer.hasPrice && customer.lastCustomerMsgDays >= 3) {
138	    return { stage: 3, label: '报价已发·等回应', action: '3-5天后温和跟进(确认收到+提供新价值)，不要催单。' };
139	  }
140	  if (customer.realMsgs < 10 && customer.daysAgo <= 2) {
141	    return { stage: 4, label: '初询阶段', action: '确认数量+目的地 → 给报价 → 引导选款。时效：24h内。' };
142	  }
143	  if (customer.realMsgs <= 5 && customer.lastCustomerMsgDays >= 3) {
144	    return { stage: 5, label: '模板提问后沉默', action: '换策略重联：给选择题而非开放式问题，给具体产品推荐。' };
145	  }
146	  return { stage: 6, label: '低意向/非采购', action: '不投入时间，标记待观察。' };
147	}
148	
149	// ===================== 沉默风险检测 =====================
150	
151	function checkSilence(customer, rules) {
152	  const silence = rules.silence_warnings[customer.tier];
153	  if (!silence) return 'normal';
154	  const d = customer.lastCustomerMsgDays;
155	  if (d === undefined) return 'unknown';
156	  if (d >= silence.danger) return 'danger';
157	  if (d >= silence.warning) return 'warning';
158	  return 'normal';
159	}
160	
161	// ===================== Excel 生成 =====================
162	
163	async function generateExcel(customers, rules, today) {
164	  const wb = new ExcelJS.Workbook();
165	  const ws = wb.addWorksheet('客户看板');
166	
167	  const headers = [
168	    '优先级', '梯队', '客户名', '国家', '阶段', '距今天数',
169	    '消息总数', '客户消息', '我方消息', '客户占比',
170	    'PI', '地址', '下单信号', '报价', '样品', '运费',
171	    '最近我方消息', '最近客户消息', '分类理由', '行动建议', '沉默风险'
172	  ];
173	
174	  const headerRow = ws.addRow(headers);
175	  headerRow.font = { bold: true, color: { argb: 'FFFFFFFF' } };
176	  headerRow.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF2F5496' } };
177	  headerRow.alignment = { vertical: 'middle', horizontal: 'center' };
178	
179	  // 颜色定义
180	  const tierColors = {
181	    p0: { argb: 'FFFFC7CE' }, // 红色
182	    p1: { argb: 'FFFFEB9C' }, // 黄色
183	    p2: { argb: 'FFC6EFCE' }, // 绿色
184	    p3: { argb: 'FFBDD7EE' }, // 蓝色
185	    p4: { argb: 'FFD9D9D9' }  // 灰色
186	  };
187	  const silenceColors = {
188	    danger: { argb: 'FFFF4444' },
189	    warning: { argb: 'FFFFAA00' }
190	  };
191	
192	  for (const c of customers) {
193	    const stage = determineStage(c);
194	    const silence = checkSilence(c, rules);
195	
196	    const row = ws.addRow([
197	      c.score.toFixed(0),
198	      `${c.tier.toUpperCase()} - ${c.tierLabel}`,
199	      c.name || '(未知)',
200	      c.country || '',
201	      stage.label,
202	      c.daysAgo ?? '',
203	      c.msgCount ?? '',
204	      c.customerMsgs ?? '',
205	      c.ourMsgs ?? '',
206	      c.cRatio != null ? `${c.cRatio}%` : '',
207	      c.hasPI ? '✓' : '',
208	      c.hasAddress ? '✓' : '',
209	      c.hasOrderSignal ? '✓' : '',
210	      c.hasPrice ? '✓' : '',
211	      c.hasSample ? '✓' : '',
212	      c.hasFreight ? '✓' : '',
213	      (c.latestOurMsg || '').substring(0, 60),
214	      (c.latestCustMsg || '').substring(0, 60),
215	      c.tierReason || '',
216	      stage.action,
217	      silence === 'danger' ? '严重' : silence === 'warning' ? '注意' : ''
218	    ]);
219	
220	    // 行着色
221	    const bg = tierColors[c.tier] || tierColors.p4;
222	    row.eachCell((cell, colNum) => {
223	      cell.fill = { type: 'pattern', pattern: 'solid', fgColor: bg };
224	      cell.alignment = { vertical: 'middle', wrapText: true };
225	    });
226	
227	    // 沉默风险着色
228	    if (silence === 'danger' || silence === 'warning') {
229	      const silenceCell = row.getCell(21);
230	      silenceCell.font = { bold: true, color: { argb: silence === 'danger' ? 'FFFF0000' : 'FFFF8800' } };
231	    }
232	  }
233	
234	  // 列宽
235	  ws.columns = headers.map((h, i) => {
236	    const widths = [7, 16, 20, 7, 16, 8, 7, 7, 7, 8, 5, 5, 7, 5, 5, 5, 40, 40, 28, 44, 7];
237	    return { width: widths[i] || 12 };
238	  });
239	
240	  // 冻结首行
241	  ws.views = [{ state: 'frozen', ySplit: 1 }];
242	
243	  // 自动筛选
244	  ws.autoFilter = { from: 'A1', to: `U${customers.length + 1}` };
245	
246	  const outPath = path.join(OUTPUT_DIR, `daily_${today}.xlsx`);
247	  await wb.xlsx.writeFile(outPath);
248	  console.log(`[DONE] Excel 看板 → ${outPath}`);
249	  return outPath;
250	}
