296	      md += `| ${i + 1} | ${c.name} | ${c.country} | ${c.daysAgo}d | ${stage.label} | ${c.tierReason} | ${(c.latestCustMsg || '').substring(0, 50)} | ${stage.action} |\n`;
297	    });
