339	// ===================== 统计输出 =====================
340	
341	function printStats(customers, rules) {
342	  const tiers = { p0: [], p1: [], p2: [], p3: [], p4: [] };
343	  const countries = {};
344	  for (const c of customers) {
345	    if (tiers[c.tier]) tiers[c.tier].push(c);
346	    if (c.country) countries[c.country] = (countries[c.country] || 0) + 1;
