    if (isFromUs(msg)) {
      ours++;
      if (ts > 0) {
        latestOurText = text;
        allTexts.push(text);
      }
    } else if (isFromCustomer(msg)) {
      cust++;
      if (ts > lastCustomerTime) lastCustomerTime = ts;
      latestCustText = text;
      allTexts.push(text);
      custTexts.push(text);
    }
  }

