    sysMsgs: sys,
    realMsgs: real,
    cRatio,
    lastCustomerMsgDays,
    latestOurMsg: latestOurText.substring(0, 200),
    latestCustMsg: latestCustText.substring(0, 200),
    ...keywords
  };
}

// ===================== 主流程 =====================

function main() {
  console.log('[START] 全量特征提取');

  // 1. 加载元数据
  const metaPath = path.join(DATA_DIR, 'tm_conversations_latest.json');
  if (!fs.existsSync(metaPath)) {
    console.error('[ERROR] 元数据不存在，先运行 sync_okki.js');
    process.exit(1);
  }
  const metaData = JSON.parse(fs.readFileSync(metaPath, 'utf-8'));
  const convs = metaData.conversations || [];
  const metaMap = {};
  for (const c of convs) metaMap[c.cid] = c;
  console.log(`[META] ${convs.length} 个客户元数据`);

  // 2. 遍历 chat_history
  const files = fs.readdirSync(CHAT_DIR).filter(f => f.endsWith('.json'));
  console.log(`[FILES] ${files.length} 个聊天记录文件`);

  const results = [];
  let skipped = 0;

  for (const file of files) {
    const filepath = path.join(CHAT_DIR, file);
    // cid from filename: replace _ with # and remove .json
    const cid = file.replace('.json', '').replace(/_/g, '#');
    // Note: the filename uses _ instead of #, so "133160999820-2500000853693_11011_icbu.json"
    // maps to cid "133160999820-2500000853693#11011@icbu"
    // But actually the _ replacement is more nuanced - only the last underscore parts
    // Let me use a different approach: just match by filename pattern
    const meta = metaMap[cid];
    const extracted = extractOne(filepath, meta);
    if (extracted) {
      results.push(extracted);
    } else {
      skipped++;
    }
  }

  // 3. 补充纯元数据客户（没有 chat_history 文件的）
  const hasChat = new Set(results.map(r => r.cid));
  for (const conv of convs) {
    if (hasChat.has(conv.cid)) continue;
    const daysAgo = conv.lastContactTime
      ? Math.floor((NOW - conv.lastContactTime) / 86400000)
      : 999;
    const latestMsg = conv.latestMessage || {};
    const isLatestFromCust = latestMsg.messageType === 'received';
    results.push({
      cid: conv.cid,
      filename: '',
      name: conv.name || conv.companyName || '(未知)',
      country: conv.complianceCountryCode || '',
      isCore: (conv.tagInfo || []).includes('3P4KK0L1O5A501H'),
      daysAgo,
      msgCount: 0, customerMsgs: 0, ourMsgs: 0, sysMsgs: 0, realMsgs: 0,
      cRatio: 0,
      lastCustomerMsgDays: isLatestFromCust ? daysAgo : 999,
      latestOurMsg: '',
      latestCustMsg: isLatestFromCust ? (latestMsg.content || '') : '',
      hasPI: false, hasAddress: false, hasOrderSignal: false,
      hasPrice: false, hasSample: false, hasFreight: false,
      hasMOQ: false, hasQuantity: false
    });
  }

  // 4. 输出
  const outPath = path.join(DATA_DIR, 's1_enhanced_full.json');
  fs.writeFileSync(outPath, JSON.stringify(results, null, 2), 'utf-8');
  console.log(`[DONE] 输出: ${outPath}`);
  console.log(`  总计: ${results.length} 个客户`);
  console.log(`  有聊天记录: ${results.filter(r => r.filename).length}`);
  console.log(`  纯元数据: ${results.filter(r => !r.filename).length}`);

  // 统计
  const stats = { p0_signals: 0, pi: 0, addr: 0, order: 0, price: 0, sample: 0 };
  for (const r of results) {
    if (r.hasPI) stats.pi++;
    if (r.hasAddress) stats.addr++;
    if (r.hasOrderSignal) stats.order++;
    if (r.hasPrice) stats.price++;
    if (r.hasSample) stats.sample++;
  }
  console.log(`  有PI: ${stats.pi} | 有地址: ${stats.addr} | 有下单信号: ${stats.order} | 有报价: ${stats.price} | 有样品: ${stats.sample}`);
}

main();
